use chrono::{Local, Utc};
use clap::{App, Arg};

fn main() {
    let matches = App::new("date_time")
        .version("1.0")
        .author("Your Name")
        .about("Displays the current date and time")
        .arg(
            Arg::with_name("time_zone")
                .long("time_zone")
                .help("Specify the time zone")
                .takes_value(true),
        )
        .get_matches();

    let time_zone = matches.value_of("time_zone").unwrap_or("UTC");
    let now = match time_zone {
        "UTC" => Utc::now(),
        _ => Local::now(),
    };

    println!("Current date and time in {}: {}", time_zone, now);
}
