use git2::{Repository, RemoteCallbacks};
use anyhow::{Result, Context};
use log::{info, error};
use env_logger::Env;

fn main() -> Result<()> {
    env_logger::init_from_env(Env::default().default_filter_or("info"));

    let repo_url = "https://github.com/rust-lang/rust.git";
    let repo_path = "rust-lang/rust";

    let callbacks = RemoteCallbacks::new();
    callbacks.progress(|progress| {
        info!("Cloning repository: {}", progress);
        Ok(())
    });

    let repo = git2::Repository::clone_bare(repo_url, repo_path, &callbacks)
        .context("Failed to clone repository")?;

    let remote = repo.find_remote("origin")?;
    let remote_url = remote.url().context("Failed to get remote URL")?;

    info!("Repository cloned from: {}", remote_url);

    let commits = repo.revparse_single("HEAD")?.into_iter().take(10).collect::<Vec<_>>();
    for commit in commits {
        let message = commit.short_message().context("Failed to get commit message")?;
        info!("Commit: {}", message);
    }

    Ok(())
}
