use aes_gcm::{Aes256, Nonce};
use aes_gcm::aead::{Aead, NewAead};
use rand::Rng;
use base64;
use hex;

fn encrypt(plaintext: &[u8], key: &[u8]) -> String {
    let mut rng = rand::thread_rng();
    let nonce = Nonce::from_slice(&[0u8; 12]);
    let cipher = Aes256::new(key);
    let ciphertext = cipher.encrypt(nonce, plaintext).unwrap();
    let encoded_nonce = base64::encode(nonce.as_bytes());
    let encoded_ciphertext = base64::encode(ciphertext);
    format!("{}:{}", encoded_nonce, encoded_ciphertext)
}

fn decrypt(ciphertext: &str, key: &[u8]) -> String {
    let parts: Vec<&str> = ciphertext.split(':').collect();
    if parts.len() != 2 {
        panic!("Invalid ciphertext format");
    }
    let encoded_nonce = parts[0];
    let encoded_ciphertext = parts[1];
    let nonce = base64::decode(encoded_nonce).unwrap();
    let cipher = Aes256::new(key);
    let ciphertext = base64::decode(encoded_ciphertext).unwrap();
    let plaintext = cipher.decrypt(nonce, ciphertext).unwrap();
    String::from_utf8(plaintext).unwrap()
}

fn main() {
    let key = [0u8; 32];
    let plaintext = "Hello, World!";
    let ciphertext = encrypt(plaintext.as_bytes(), &key);
    println!("Ciphertext: {}", ciphertext);
    let decrypted = decrypt(&ciphertext, &key);
    println!("Decrypted: {}", decrypted);
}
```

This code uses the `aes_gcm` crate to implement AES encryption and decryption. It generates a random nonce for each encryption operation and encodes the nonce and ciphertext using base64. The `decrypt` function decodes the nonce and ciphertext, and then decrypts the ciphertext using the provided key.

