pub enum MyError {
    #[error("IO error: {0}")]
    Io(#[from] std::io::Error),

    #[error("Custom error: {0}")]
    Custom(String),

    #[error("Invalid input: {0}")]
    InvalidInput(String),

    #[error("Network error: {0}")]
    Network(#[from] std::net::Error),

    #[error("Other error: {0}")]
    Other(#[from] Box<dyn std::error::Error>),
}

impl std::fmt::Display for MyError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            MyError::Io(err) => write!(f, "IO error: {}", err),
            MyError::Custom(msg) => write!(f, "Custom error: {}", msg),
            MyError::InvalidInput(msg) => write!(f, "Invalid input: {}", msg),
            MyError::Network(err) => write!(f, "Network error: {}", err),
            MyError::Other(err) => write!(f, "Other error: {}", err),
        }
    }
}

impl std::error::Error for MyError {}

impl std::error::Source for MyError {
    fn source(&self) -> Option<&(dyn std::error::Error + 'static)> {
        match self {
            MyError::Io(err) => Some(err),
            MyError::Network(err) => Some(err),
            _ => None,
        }
    }
}

