            transform: Transform::from_translation(Vec3::new(0.0, 0.0, 3.0)),
            ..default()
        })
        .insert(Name::new("Camera"));

    // Create a light
    commands
        .spawn(LightBundle {
            transform: Transform::from_translation(Vec3::new(0.0, 0.0, 5.0)),
            ..default()
        })
        .insert(Name::new("Light"));

    // Create a cube entity
