use async_trait::async_trait;
use backoff::{backoff::Backoff, ExponentialBackoff};
use futures::FutureExt;
use log::{debug, error};
use retry::{Retry, RetryError};

// Define a trait for retryable async functions
#[async_trait]
trait Retryable {
    async fn retryable(self) -> Result<Self, RetryError>;
}

// Implement retry mechanism for async functions
#[async_trait]
impl<T, E> Retryable for T
where
    T: Future<Output = Result<(), E>>,
    E: std::error::Error + Send + Sync + 'static,
{
    async fn retryable(self) -> Result<Self, RetryError> {
        let retry = Retry::new(
            self,
            ExponentialBackoff::default(),
            5, // max attempts
            10, // max jitter
        );

        match retry.run().await {
            Ok(output) => output,
            Err(retry_error) => {
                error!("Retry failed: {}", retry_error);
                Err(retry_error)
            }
        }
    }
}

// Example usage
#[tokio::main]
async fn main() {
    let attempt = async {
        // Simulate a transient error
        if rand::random::<f64>() < 0.5 {
            return Err("Transient error".into());
        }
        Ok(())
    };

    let result = attempt.retryable().await;
    match result {
        Ok(_) => debug!("Operation successful"),
        Err(e) => error!("Operation failed: {}", e),
    }
}
```

