use gnuplot::{Config, Data, Plot, PlotBuilder};
use rand::Rng;
use std::thread;
use num_cpus;

fn main() {
    let n = 1000;
    let mut data = vec![0.0; n];
    let mut rng = rand::thread_rng();

    for i in 0..n {
        data[i] = rng.gen::<f64>();
    }

    let plot = PlotBuilder::new()
        .set_title("Random Data")
        .set_xlabel("Index")
        .set_ylabel("Value")
        .set_data(Data::new("x", &data.iter().enumerate().map(|(i, _)| i as f64).collect::<Vec<_>>(), "y", &data))
        .set_terminal("png")
        .set_size(800, 600)
        .build();

    let num_threads = num_cpus::get();
    let mut handles = vec![];

    for i in 0..num_threads {
        let plot = plot.clone();
        let handle = thread::spawn(move || {
            plot.save(format!("plot_{}.png", i)).unwrap();
        });
        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }
}
