use deadpool_postgres::{Pool, Config};
use async_trait::async_trait;
use tokio_postgres::{NoTls, Row};
use tokio::sync::RwLock;

#[async_trait]
trait PoolConnection {
    async fn execute(&self, query: &str) -> Result<Vec<Row>, deadpool_postgres::Error>;
    async fn query(&self, query: &str) -> Result<Vec<Row>, deadpool_postgres::Error>;
}

#[async_trait]
impl PoolConnection for Pool {
    async fn execute(&self, query: &str) -> Result<Vec<Row>, deadpool_postgres::Error> {
        self.get().await?.execute(query).await
    }

    async fn query(&self, query: &str) -> Result<Vec<Row>, deadpool_postgres::Error> {
        self.get().await?.query(query).await
    }
}

#[tokio::main]
async fn main() {
    let config = Config::new("host=localhost user=postgres password=postgres dbname=postgres");
    let pool = Pool::new(config).await.unwrap();

    let pool = RwLock::new(pool);

    let mut conn = pool.write().await;
    let rows = conn.execute("SELECT * FROM users").await.unwrap();

    for row in rows {
        println!("{:?}", row);
    }
}
