use serde::{Serialize, Serializer};
use regex::Regex;
use std::fmt;

// Define a custom error type for serialization errors
#[derive(Debug)]
pub enum SerializeError {
    InvalidCharacter(char),
}

impl std::error::Error for SerializeError {}

impl fmt::Display for SerializeError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            SerializeError::InvalidCharacter(c) => write!(f, "Invalid character: {}", c),
        }
    }
}

// Define a custom serializer for plain text with restrictions
pub struct RestrictedTextSerializer;

impl Serializer for RestrictedTextSerializer {
    type Ok = String;
    type Error = SerializeError;
    type Output = Result<Self::Ok, Self::Error>;

    fn serialize<S>(&self, value: &S) -> Result<Self::Output, S::Error>
    where
        S: Serializer,
    {
        let restricted_chars = "[^a-zA-Z0-9\\s]";
        let pattern = Regex::new(restricted_chars).unwrap();
        let text = value.to_string();
        let cleaned_text = pattern.replace_all(&text, "");

        if cleaned_text.is_empty() {
            Err(SerializeError::InvalidCharacter(text.chars().next().unwrap()))
        } else {
            Ok(cleaned_text)
        }
    }
}
