// Define a Node struct to represent a node in the tree
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
struct Node {
    id: u32,
    value: u32,
    children: Vec<u32>,
}

// Define a Tree struct to represent the tree data structure
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
struct Tree {
    nodes: Vec<Node>,
    id_map: HashMap<u32, usize>,
}

impl Tree {
    // Create a new tree with an empty vector of nodes
    fn new() -> Self {
        Tree {
            nodes: Vec::new(),
            id_map: HashMap::new(),
        }
    }

    // Add a new node to the tree
    fn add_node(&mut self, value: u32) -> u32 {
        let id = self.nodes.len() as u32 + 1;
        let node = Node {
            id,
            value,
            children: Vec::new(),
        };
        self.nodes.push(node);
        self.id_map.insert(id, self.nodes.len() - 1);
        id
    }

    // Get a node by its ID
    fn get_node(&self, id: u32) -> Option<&Node> {
        self.id_map.get(&id).map(|index| &self.nodes[*index])
    }

    // Add a child to a node
    fn add_child(&mut self, parent_id: u32, child_id: u32) {
        let parent_index = self.id_map.get(&parent_id).unwrap();
        let child_index = self.id_map.get(&child_id).unwrap();
        self.nodes[*parent_index].children.push(*child_index);
    }
}

impl fmt::Display for Tree {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        let mut nodes = self.nodes.clone();
        nodes.sort_by_key(|node| node.id);
        for node in nodes {
            write!(f, "Node {}: value = {}, children = {:?}", node.id, node.value, node.children)?;
        }
        Ok(())
    }
}

