use std::thread;
use std::sync::Arc;
use std::sync::atomic::{AtomicUsize, Ordering};
use crossbeam::atomic::AtomicCell;
use num_cpus::get;
use libc::{cpu_set_t, CPU_SET, CPU_ZERO, sched_setaffinity, sched_getaffinity};

const CPU_SETSIZE: usize = 1024;

struct CpuAffinityManager {
    affinity: AtomicCell<cpu_set_t>,
}

impl CpuAffinityManager {
    fn new() -> Self {
        let affinity = AtomicCell::new(cpu_set_t::default());
        Self { affinity }
    }

    fn set_affinity(&self, thread_id: usize, core_id: usize) {
        let mut affinity = self.affinity.load(Ordering::SeqCst);
        CPU_ZERO(&mut affinity);
        CPU_SET(core_id, &mut affinity);
        self.affinity.store(affinity, Ordering::SeqCst);
        let mut affinity = cpu_set_t::default();
        CPU_ZERO(&mut affinity);
        CPU_SET(core_id, &mut affinity);
        unsafe {
            sched_setaffinity(thread_id, &mut affinity as *mut _ as *mut _);
        }
    }

    fn get_affinity(&self, thread_id: usize) -> Option<usize> {
        let affinity = self.affinity.load(Ordering::SeqCst);
        for i in 0..get() {
            if CPU_ISSET(i, &affinity) {
                return Some(i);
            }
        }
        None
    }
}

