[bitreader, bitvec, bytesize]

```rust
use bitvec::BitVec;
use bytesize::Bytesize;

pub struct BitReader<'a> {
    buffer: &'a [u8],
    position: usize,
}

impl<'a> BitReader<'a> {
    pub fn new(buffer: &'a [u8]) -> Self {
        Self { buffer, position: 0 }
    }

    pub fn read_bits(&mut self, count: usize) -> BitVec {
        assert!(count <= 8 * self.buffer.len() as usize);

        let mut result = BitVec::with_capacity(count);
        for _ in 0..count {
            let byte = self.buffer[self.position / 8];
            let bit = (byte >> (7 - (self.position % 8))) & 1;
            result.push(bit);
            self.position += 1;
        }
        result
    }

    pub fn read_bits_at(&mut self, position: usize, count: usize) -> BitVec {
        assert!(position + count <= 8 * self.buffer.len() as usize);

        let mut result = BitVec::with_capacity(count);
        for _ in 0..count {
            let byte = self.buffer[position / 8];
            let bit = (byte >> (7 - (position % 8))) & 1;
            result.push(bit);
            position += 1;
        }
        result
    }

    pub fn position(&self) -> usize {
        self.position
    }

    pub fn bytesize(&self) -> Bytesize {
        Bytesize::from(self.position)
    }
}
```

Example usage:

```rust
fn main() {
    let buffer = b"Hello, World!";
    let mut reader = BitReader::new(buffer);

    let bits = reader.read_bits(13);
    println!("{:?}", bits);

    let bits = reader.read_bits_at(10, 5);
    println!("{:?}", bits);

    println!("Position: {}", reader.position());
    println!("Bytesize: {}", reader.bytesize());
}
```

