use std::sync::{Arc, Mutex};
use std::marker::Send;
use std::panic::{panic_any, AssertUnreachable};

pub struct SendWrapper<T> {
    inner: Arc<Mutex<T>>,
}

impl<T> SendWrapper<T> {
    pub fn new(value: T) -> Self {
        SendWrapper(Arc::new(Mutex::new(value)))
    }

    pub fn get(&self) -> T {
        self.inner.lock().unwrap().clone()
    }

    pub fn set(&self, value: T) {
        *self.inner.lock().unwrap() = value;
    }
}

impl<T> Drop for SendWrapper<T>
where
    T: Send,
{
    fn drop(&mut self) {
        // Ensure this is called on the original thread
        std::thread::current().unwrap().id();
        // Ensure the value is not accessed after drop
        std::mem::forget(self.inner.lock().unwrap());
    }
}

impl<T> Send for SendWrapper<T> {
    fn send(&self, _to: &Self::Target) -> Self::Sent {
        // Panic if not Send
        panic_any("SendWrapper<T> is not Send");
    }
}

impl<T> Sync for SendWrapper<T> {
    fn get_mut(&mut self) -> Option<&mut Self> {
        // Panic if not Sync
        panic_any("SendWrapper<T> is not Sync");
        None
    }
}
```

