use chrono::{Duration, Local};
use std::thread;
use std::time::Instant;

pub struct Stopwatch {
    start_time: Instant,
    stopped: bool,
}

impl Stopwatch {
    pub fn new() -> Self {
        Self {
            start_time: Instant::now(),
            stopped: false,
        }
    }

    pub fn start(&mut self) {
        if self.stopped {
            self.start_time = Instant::now();
            self.stopped = false;
        }
    }

    pub fn stop(&mut self) {
        if !self.stopped {
            self.stopped = true;
        }
    }

    pub fn elapsed(&self) -> Duration {
        if self.stopped {
            return Duration::from_secs(0);
        }
        self.start_time.elapsed()
    }

    pub fn elapsed_seconds(&self) -> f64 {
        self.elapsed().as_secs() as f64 + self.elapsed().as_millis() as f64 / 1000.0
    }

    pub fn elapsed_minutes(&self) -> f64 {
        self.elapsed_seconds() / 60.0
    }

    pub fn elapsed_hours(&self) -> f64 {
        self.elapsed_minutes() / 60.0
    }
}

fn main() {
    let mut stopwatch = Stopwatch::new();
    stopwatch.start();

    thread::sleep(std::time::Duration::from_secs(5));

    println!("Elapsed time: {} seconds", stopwatch.elapsed_seconds());
    println!("Elapsed time: {} minutes", stopwatch.elapsed_minutes());
    println!("Elapsed time: {} hours", stopwatch.elapsed_hours());
}
```

