use zip::read::ZipFile;
use base64;
use crypto_mac::{Mac, MacResult};
use crypto_hash::{Digest, DigestResult};
use crypto_random::Rng;
use env_logger::Env;

fn main() {
    env_logger::Builder::from_env(Env::default().default_filter_or("info")).init();

    let password = "mysecretpassword";
    let file_path = "example.txt";
    let output_path = "example.zip";

    // Compress file with password protection
    compress_with_password(file_path, output_path, password);

    // Decompress file with password protection
    decompress_with_password(output_path, file_path, password);

    // Compress file with custom compression level
    compress_with_custom_level(file_path, output_path, 6);

    // Decompress file
    decompress_file(output_path, file_path);
}

fn compress_with_password(input_path: &str, output_path: &str, password: &str) {
    let mut rng = Rng::new().unwrap();
    let mut zip_file = ZipWriter::new(io::BufWriter::new(fs::File::create(output_path).unwrap()));
    let mut file = fs::File::open(input_path).unwrap();
    let mut password_hash = [0u8; 32];
    rng.fill_bytes(&mut password_hash);
    let mut mac = Mac::new(crypto_mac::Hmac::new(crypto_hash::Blake2b::new(), &password_hash));
    let mut buffer = [0u8; 4096];
    loop {
        let count = file.read(&mut buffer).unwrap();
        if count == 0 {
            break;
        }
        let mut encrypted_buffer = [0u8; 4096];
        mac.update(&buffer[..count]);
        let tag = mac.finalize();
        for i in 0..count {
            encrypted_buffer[i] = buffer[i] ^ tag.bytes[i];
        }
        zip_file.start_file(input_path, FileOptions::default()).unwrap();
        zip_file.write_all(&encrypted_buffer[..count]).unwrap();
    }
    zip_file.finish().unwrap();
}

