use std::alloc::{Layout, GlobalAlloc};
use std::sync::Once;
use std::thread;
use std::marker::PhantomData;
use std::cell::RefCell;

static ALLOCATOR: Once = Once::new();
static mut GLOBAL_ALLOCATOR: Option<Box<dyn GlobalAlloc>> = None;

struct Arena<T> {
    data: Vec<u8>,
    layout: Layout,
    phantom: PhantomData<T>,
}

impl<T> Arena<T> {
    fn new() -> Self {
        let layout = Layout::from_size_align(1024, 16).unwrap();
        let data = Vec::with_capacity(layout.size() as usize);
        Arena {
            data,
            layout,
            phantom: PhantomData,
        }
    }

    fn alloc(&mut self) -> *mut T {
        let layout = Layout::from_size_align(self.layout.size(), self.layout.align()).unwrap();
        let ptr = self.data.as_mut_ptr() as *mut T;
        self.data.set_len(self.data.len() + layout.size() as usize);
        ptr
    }
}

unsafe impl<T> GlobalAlloc for Arena<T> {
    fn alloc(&self, layout: Layout) -> *mut u8 {
        self.alloc()
    }

    fn dealloc(&self, ptr: *mut u8, _layout: Layout) {
        // Do nothing, arena will be dropped when it goes out of scope
    }
}

thread_local! {
    static ARENA: RefCell<Arena<Box<dyn Drop>>> = RefCell::new(Arena::new());
}

pub fn get_arena() -> &'static mut Arena<Box<dyn Drop>> {
    ALLOCATOR.call_once(|| {
        unsafe {
            GLOBAL_ALLOCATOR = Some(Box::leak(Box::new(Arena::new())));
        }
    });
    unsafe { &mut *GLOBAL_ALLOCATOR.as_mut().unwrap() }
}

pub struct Temp<T> {
    arena: &'static mut Arena<Box<dyn Drop>>,
    ptr: *mut T,
}

impl<T> Drop for Temp<T> {
    fn drop(&mut self) {
        unsafe { (&mut *self.ptr).drop(); }
    }
}

impl<T> Temp<T> {
    pub fn new() -> Self {
        let arena = get_arena();
        let ptr = arena.alloc();
        Temp { arena, ptr }
    }
}

